/**
 * ID로 60갑자 조회
 * @param id 0~59
 * @returns 60갑자 정보
 */
function getPillarById(id) {
    if (id < 0 || id >= 60) {
        throw new RangeError(`Pillar ID must be 0~59, got ${id}`);
    }
    return SIXTY_PILLARS[id];
}
/**
 * 한글 갑자로 60갑자 조회
 * @param hangul 갑자 (예: "갑자", "을축")
 * @returns 60갑자 정보 또는 undefined
 */
function getPillarByHangul(hangul) {
    return SIXTY_PILLARS.find(p => p.combined.hangul === hangul);
}

/**
 * 갑자 계산 모듈
 *
 * 60갑자 데이터를 사용하여 갑자 계산을 수행합니다.
 */
/**
 * 갑자 ID(0~59)로 한글/한자 이름 생성
 * @param yearPillarId 년주 ID (0~59)
 * @param monthPillarId 월주 ID (0~59)
 * @param dayPillarId 일주 ID (0~59)
 * @returns 갑자 정보
 */
function formatGapjaByIds(yearPillarId, monthPillarId, dayPillarId) {
    const year = getPillarById(yearPillarId);
    const month = getPillarById(monthPillarId);
    const day = getPillarById(dayPillarId);
    return {
        yearPillar: year.combined.hangul,
        yearPillarHanja: year.combined.hanja,
        monthPillar: month.combined.hangul,
        monthPillarHanja: month.combined.hanja,
        dayPillar: day.combined.hangul,
        dayPillarHanja: day.combined.hanja,
    };
}

/**
 * 양력 ↔ 음력 변환 모듈
 *
 * 만세력 인덱스를 사용하여 양력과 음력 간 변환을 수행합니다.
 */
/**
 * 양력 → 음력 변환
 * @param solarYear 양력 년 (1000~2050)
 * @param solarMonth 양력 월 (1~12)
 * @param solarDay 양력 일 (1~31)
 * @returns 음력 날짜와 갑자 정보
 * @throws {OutOfRangeError} 지원 범위 밖 연도
 * @throws {InvalidDateError} 유효하지 않은 날짜
 */
function solarToLunar(solarYear, solarMonth, solarDay) {
    // 1. 범위 검증
    if (!isSupportedYear(solarYear)) {
        throw new OutOfRangeError(solarYear);
    }
    // 2. 월별 인덱스 조회
    `${solarYear}-${String(solarMonth).padStart(2, '0')}`;
    const monthIndex = getMonthlyIndex(solarYear, solarMonth);
    if (!monthIndex) {
        throw new InvalidDateError(`No data found for ${solarYear}-${solarMonth}`);
    }
    // 3. 월 내에서 해당 날짜 찾기
    const entry = monthIndex.entries.find(e => e.solar.year === solarYear && e.solar.month === solarMonth && e.solar.day === solarDay);
    if (!entry) {
        throw new InvalidDateError(`Invalid solar date: ${solarYear}-${solarMonth}-${solarDay}`);
    }
    // 4. 갑자 계산
    const gapja = formatGapjaByIds(entry.gapja.yearPillarId, entry.gapja.monthPillarId, entry.gapja.dayPillarId);
    // 5. 결과 반환
    return {
        solar: { year: solarYear, month: solarMonth, day: solarDay },
        lunar: {
            year: entry.lunar.year,
            month: entry.lunar.month,
            day: entry.lunar.day,
            isLeapMonth: entry.lunar.isLeap,
        },
        gapja,
        julianDay: entry.jd,
    };
}
/**
 * 음력 → 양력 변환
 * @param lunarYear 음력 년 (1000~2050)
 * @param lunarMonth 음력 월 (1~12)
 * @param lunarDay 음력 일 (1~30)
 * @param isLeapMonth 윤달 여부
 * @returns 양력 날짜와 갑자 정보
 * @throws {OutOfRangeError} 지원 범위 밖 연도
 * @throws {InvalidDateError} 유효하지 않은 날짜
 */
function lunarToSolar(lunarYear, lunarMonth, lunarDay, isLeapMonth = false) {
    // 1. 범위 검증
    if (!isSupportedYear(lunarYear)) {
        throw new OutOfRangeError(lunarYear);
    }
    // 2. 음력 → 양력 역인덱스 조회
    // 전체 인덱스를 순회하며 일치하는 항목 찾기
    for (let month = 1; month <= 12; month++) {
        const monthIndex = getMonthlyIndex(lunarYear, month);
        if (!monthIndex)
            continue;
        const entry = monthIndex.entries.find(e => e.lunar.year === lunarYear &&
            e.lunar.month === lunarMonth &&
            e.lunar.day === lunarDay &&
            e.lunar.isLeap === isLeapMonth);
        if (entry) {
            // 갑자 계산
            const gapja = formatGapjaByIds(entry.gapja.yearPillarId, entry.gapja.monthPillarId, entry.gapja.dayPillarId);
            return {
                lunar: { year: lunarYear, month: lunarMonth, day: lunarDay, isLeapMonth },
                solar: {
                    year: entry.solar.year,
                    month: entry.solar.month,
                    day: entry.solar.day,
                },
                gapja,
            };
        }
    }
    throw new InvalidDateError(`Invalid lunar date: ${lunarYear}-${lunarMonth}-${lunarDay}${isLeapMonth ? ' (leap)' : ''}`);
}
/**
 * 특정 날짜의 갑자 계산
 * @param solarYear 양력 년
 * @param solarMonth 양력 월
 * @param solarDay 양력 일
 * @returns 갑자 정보
 */
function getGapja(solarYear, solarMonth, solarDay) {
    const result = solarToLunar(solarYear, solarMonth, solarDay);
    return {
        yearPillar: result.gapja.yearPillar,
        yearPillarHanja: result.gapja.yearPillarHanja,
        monthPillar: result.gapja.monthPillar,
        monthPillarHanja: result.gapja.monthPillarHanja,
        dayPillar: result.gapja.dayPillar,
        dayPillarHanja: result.gapja.dayPillarHanja,
    };
}

/**
 * 사주팔자 계산 모듈
 *
 * 사주팔자(년주, 월주, 일주, 시주)를 계산합니다.
 */
/**
 * 사주팔자 계산
 *
 * @param solarYear 양력 년
 * @param solarMonth 양력 월 (1~12)
 * @param solarDay 양력 일 (1~31)
 * @param solarHour 양력 시 (0~23)
 * @param solarMinute 양력 분 (0~59, 기본값: 0)
 * @param options 사주 계산 옵션
 * @returns 사주팔자 정보
 */
function calculateSaju(solarYear, solarMonth, solarDay, solarHour, solarMinute = 0, options = {}) {
    const { longitude = 127, applyTimeCorrection = true, } = options;
    // 갑자 계산 (년주, 월주, 일주)
    const gapja = getGapja(solarYear, solarMonth, solarDay);
    // 시주 계산
    let hourPillar = null;
    let hourPillarHanja = null;
    let isTimeCorrected = false;
    let correctedTime;
    if (solarHour !== undefined) {
        let calcHour = solarHour;
        let calcMinute = solarMinute;
        // 시간 보정 (진태양시)
        if (applyTimeCorrection) {
            const standardMeridian = 135; // 한국 표준시 자오선 (UTC+9)
            const degreesDiff = standardMeridian - longitude;
            const longitudeCorrection = Math.round(degreesDiff * 4); // 1도 = 4분
            calcMinute = solarMinute - longitudeCorrection;
            calcHour = solarHour;
            if (calcMinute < 0) {
                calcMinute += 60;
                calcHour -= 1;
            }
            if (calcHour < 0) {
                calcHour += 24;
            }
            if (longitudeCorrection !== 0) {
                isTimeCorrected = true;
                correctedTime = { hour: calcHour, minute: calcMinute };
            }
        }
        // 시지 결정 (백엔드와 동일한 로직)
        let hourBranchId;
        if (calcHour === 23 || calcHour === 0) {
            hourBranchId = 0; // 자시
        }
        else {
            hourBranchId = Math.floor((calcHour + 1) / 2);
        }
        // 오자시두법으로 시천간 결정
        const dayStem = gapja.dayPillar.charAt(0);
        const hourStemStart = getHourStemStart(dayStem);
        const hourStemId = (hourStemStart + hourBranchId) % 10;
        const stems = ['갑', '을', '병', '정', '무', '기', '경', '신', '임', '계'];
        const stemChars = ['甲', '乙', '丙', '丁', '戊', '己', '庚', '辛', '壬', '癸'];
        const branches = ['자', '축', '인', '묘', '진', '사', '오', '미', '신', '유', '술', '해'];
        const branchChars = ['子', '丑', '寅', '卯', '辰', '巳', '午', '未', '申', '酉', '戌', '亥'];
        hourPillar = stems[hourStemId] + branches[hourBranchId];
        hourPillarHanja = stemChars[hourStemId] + branchChars[hourBranchId];
    }
    return {
        yearPillar: gapja.yearPillar,
        yearPillarHanja: gapja.yearPillarHanja,
        monthPillar: gapja.monthPillar,
        monthPillarHanja: gapja.monthPillarHanja,
        dayPillar: gapja.dayPillar,
        dayPillarHanja: gapja.dayPillarHanja,
        hourPillar,
        hourPillarHanja,
        gapja,
        isTimeCorrected,
        correctedTime,
    };
}
/**
 * 오자시두법에 따른 자시 천간 시작점
 *
 * 일간에 따라 자시의 천간이 다릅니다:
 * - 갑/기일: 자시부터 갑자, 을축, 병인, ...
 * - 을/경일: 자시부터 병자, 정축, 무인, ...
 * - 병/신일: 자시부터 무자, 기축, 경인, ...
 * - 정/임일: 자시부터 경자, 신축, 임인, ...
 * - 무/계일: 자시부터 임자, 계축, 갑인, ...
 */
function getHourStemStart(dayStem) {
    const stemMap = {
        갑: 0,
        기: 0, // 갑/기 → 자시부터 갑자 (갑=0)
        을: 2,
        경: 2, // 을/경 → 자시부터 병자 (병=2)
        병: 4,
        신: 4, // 병/신 → 자시부터 무자 (무=4)
        정: 6,
        임: 6, // 정/임 → 자시부터 경자 (경=6)
        무: 8,
        계: 8, // 무/계 → 자시부터 임자 (임=8)
    };
    return stemMap[dayStem] ?? 0;
}
/**
 * 간단한 사주 계산 (시간 보정 없음)
 *
 * @param solarYear 양력 년
 * @param solarMonth 양력 월 (1~12)
 * @param solarDay 양력 일 (1~31)
 * @param solarHour 양력 시 (0~23, 선택사항)
 * @returns 사주팔자 정보
 */
function calculateSajuSimple(solarYear, solarMonth, solarDay, solarHour) {
    return calculateSaju(solarYear, solarMonth, solarDay, solarHour, 0, {
        applyTimeCorrection: false,
    });
}

